import{_ as l,o as i,c as e,ae as r}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"aside":"left"},"headers":[],"relativePath":"note/datacom技术栈.md","filePath":"note/datacom技术栈.md"}'),t={name:"note/datacom技术栈.md"};function o(n,a,P,h,s,u){return i(),e("div",null,[...a[0]||(a[0]=[r('<h3 id="一、交换机-switch-技术栈" tabindex="-1">一、交换机（Switch）技术栈 <a class="header-anchor" href="#一、交换机-switch-技术栈" aria-label="Permalink to &quot;一、交换机（Switch）技术栈&quot;">​</a></h3><p><strong>核心定位</strong>：二层 / 三层转发、局域网接入、VLAN 隔离、链路聚合</p><h4 id="_1-基础协议与转发" tabindex="-1">1. 基础协议与转发 <a class="header-anchor" href="#_1-基础协议与转发" aria-label="Permalink to &quot;1. 基础协议与转发&quot;">​</a></h4><ul><li><p>二层核心</p><p>：</p><ul><li>IEEE 802.3（以太网）、802.1Q（VLAN）、802.1D（STP）、802.1w（RSTP）、802.1s（MSTP）</li><li>MAC 地址自学习、MAC 地址表、端口隔离、端口安全</li></ul></li><li><p>三层核心（三层交换机）</p><p>：</p><ul><li>硬件 ASIC 路由、VLAN 间路由、静态路由、RIP/OSPF 基础</li></ul></li></ul><h4 id="_2-高级特性" tabindex="-1">2. 高级特性 <a class="header-anchor" href="#_2-高级特性" aria-label="Permalink to &quot;2. 高级特性&quot;">​</a></h4><ul><li><strong>链路聚合</strong>：LACP（802.3ad）、静态聚合</li><li><strong>可靠性</strong>：堆叠（Stack）、集群（CSS/IRF）、BFD、VRRP</li><li><strong>QoS</strong>：端口限速、队列调度（PQ/CBWFQ）、WRED、流量整形</li><li><strong>管理</strong>：SNMP、Telnet/SSH、Syslog、NetStream</li></ul><h4 id="_3-主流技术方向" tabindex="-1">3. 主流技术方向 <a class="header-anchor" href="#_3-主流技术方向" aria-label="Permalink to &quot;3. 主流技术方向&quot;">​</a></h4><ul><li>10G/25G/100G/400G 高速接口</li><li>白盒交换机、SDN/OpenFlow、EVPN-VXLAN（数据中心）</li></ul><hr><h3 id="二、路由器-router-技术栈" tabindex="-1">二、路由器（Router）技术栈 <a class="header-anchor" href="#二、路由器-router-技术栈" aria-label="Permalink to &quot;二、路由器（Router）技术栈&quot;">​</a></h3><p><strong>核心定位</strong>：跨网络路由、广域网互联、NAT、策略路由、MPLS</p><h4 id="_1-网络层核心" tabindex="-1">1. 网络层核心 <a class="header-anchor" href="#_1-网络层核心" aria-label="Permalink to &quot;1. 网络层核心&quot;">​</a></h4><ul><li><p><strong>IP 协议</strong>：IPv4/IPv6、ICMP、ARP、DHCP、NAT（SNAT/DNAT/Easy-IP）</p></li><li><p>路由协议</p><p>：</p><ul><li>静态路由</li><li>动态：RIP（距离矢量）、OSPF（链路状态，中大型）、IS-IS（运营商）、BGP（路径矢量，AS 间）</li><li>IPv6：RIPng、OSPFv3、BGP4+</li></ul></li></ul><h4 id="_2-广域网与-vpn" tabindex="-1">2. 广域网与 VPN <a class="header-anchor" href="#_2-广域网与-vpn" aria-label="Permalink to &quot;2. 广域网与 VPN&quot;">​</a></h4><ul><li>WAN：PPP、PPPoE、HDLC、Frame Relay、MPLS、GRE、IPsec、L2TP、SSL VPN</li><li>MPLS：LDP、RSVP-TE、MPLS VPN、VPLS、EVPN</li></ul><h4 id="_3-可靠性与-qos" tabindex="-1">3. 可靠性与 QoS <a class="header-anchor" href="#_3-可靠性与-qos" aria-label="Permalink to &quot;3. 可靠性与 QoS&quot;">​</a></h4><ul><li>高可用：VRRP、BFD、NSF/GR、双机热备</li><li>QoS：CAR、LR、队列调度、流量监管、拥塞避免</li></ul><h4 id="_4-技术演进" tabindex="-1">4. 技术演进 <a class="header-anchor" href="#_4-技术演进" aria-label="Permalink to &quot;4. 技术演进&quot;">​</a></h4><ul><li>云路由、SD-WAN、SRv6、Segment Routing、自动化（NETCONF/YANG）</li></ul><hr><h3 id="三、ap-ac-无线接入点-无线控制器-技术栈" tabindex="-1">三、AP/AC（无线接入点 / 无线控制器）技术栈 <a class="header-anchor" href="#三、ap-ac-无线接入点-无线控制器-技术栈" aria-label="Permalink to &quot;三、AP/AC（无线接入点 / 无线控制器）技术栈&quot;">​</a></h3><p><strong>核心定位</strong>：无线接入、WLAN 管理、漫游、安全、射频优化</p><h4 id="_1-无线标准" tabindex="-1">1. 无线标准 <a class="header-anchor" href="#_1-无线标准" aria-label="Permalink to &quot;1. 无线标准&quot;">​</a></h4><ul><li>802.11a/b/g/n/ac/ax（Wi-Fi 6）、802.11be（Wi-Fi 7）</li><li>频段：2.4GHz、5GHz、6GHz</li></ul><h4 id="_2-架构与协议" tabindex="-1">2. 架构与协议 <a class="header-anchor" href="#_2-架构与协议" aria-label="Permalink to &quot;2. 架构与协议&quot;">​</a></h4><ul><li><strong>FAT AP（胖 AP）</strong>：独立工作，Web 管理，适合小型网络</li><li><strong>FIT AP（瘦 AP）+ AC</strong>：集中管理、CAPWAP 隧道、零配置上线、统一射频调度</li><li><strong>漫游</strong>：二层漫游、三层漫游、802.11r（快速漫游）</li></ul><h4 id="_3-安全与接入控制" tabindex="-1">3. 安全与接入控制 <a class="header-anchor" href="#_3-安全与接入控制" aria-label="Permalink to &quot;3. 安全与接入控制&quot;">​</a></h4><ul><li>加密：WPA2-PSK、WPA3、802.1X（EAP-TLS/PEAP）、Portal 认证</li><li>隔离：SSID 隔离、用户隔离、AP 隔离</li></ul><h4 id="_4-射频与优化" tabindex="-1">4. 射频与优化 <a class="header-anchor" href="#_4-射频与优化" aria-label="Permalink to &quot;4. 射频与优化&quot;">​</a></h4><ul><li>信道规划、功率调整、负载均衡、智能漫游、抗干扰、WMM（无线 QoS）</li></ul><h4 id="_5-管理" tabindex="-1">5. 管理 <a class="header-anchor" href="#_5-管理" aria-label="Permalink to &quot;5. 管理&quot;">​</a></h4><ul><li>AC 集群、AP 批量配置、无线定位、频谱分析、IoT 接入（BLE/ZigBee）</li></ul><hr><h3 id="四、防火墙-firewall-技术栈" tabindex="-1">四、防火墙（Firewall）技术栈 <a class="header-anchor" href="#四、防火墙-firewall-技术栈" aria-label="Permalink to &quot;四、防火墙（Firewall）技术栈&quot;">​</a></h3><p><strong>核心定位</strong>：访问控制、威胁防护、NAT、VPN、应用识别、零信任</p><h4 id="_1-基础防护-传统-状态检测" tabindex="-1">1. 基础防护（传统 / 状态检测） <a class="header-anchor" href="#_1-基础防护-传统-状态检测" aria-label="Permalink to &quot;1. 基础防护（传统 / 状态检测）&quot;">​</a></h4><ul><li>包过滤（五元组：源 / 目的 IP、端口、协议）、状态检测（ASPF）、会话表</li><li>NAT、策略路由、安全区域（Trust/Untrust/DMZ）、ACL</li></ul><h4 id="_2-下一代防火墙-ngfw-核心" tabindex="-1">2. 下一代防火墙（NGFW）核心 <a class="header-anchor" href="#_2-下一代防火墙-ngfw-核心" aria-label="Permalink to &quot;2. 下一代防火墙（NGFW）核心&quot;">​</a></h4><ul><li><strong>应用层防护</strong>：DPI/DFI、应用识别（如微信 / 抖音）、URL 过滤、文件过滤、IPS/IDS</li><li><strong>威胁防御</strong>：AV（防病毒）、Anti-Spam、APT 检测、威胁情报、沙箱</li><li><strong>身份集成</strong>：AD/LDAP/RADIUS、用户 - 策略绑定、单点登录</li></ul><h4 id="_3-vpn-与加密" tabindex="-1">3. VPN 与加密 <a class="header-anchor" href="#_3-vpn-与加密" aria-label="Permalink to &quot;3. VPN 与加密&quot;">​</a></h4><ul><li>IPsec/IKE、SSL VPN、L2TP/IPsec、GRE over IPsec、硬件加密引擎、PKI/RSA</li></ul><h4 id="_4-高可用与运维" tabindex="-1">4. 高可用与运维 <a class="header-anchor" href="#_4-高可用与运维" aria-label="Permalink to &quot;4. 高可用与运维&quot;">​</a></h4><ul><li>双机热备（VGMP/HRP）、负载均衡、BFD、日志审计（Syslog/NetFlow）、可视化管控</li></ul><h4 id="_5-前沿方向" tabindex="-1">5. 前沿方向 <a class="header-anchor" href="#_5-前沿方向" aria-label="Permalink to &quot;5. 前沿方向&quot;">​</a></h4><ul><li>云防火墙、SASE、零信任（ZTNA）、AI 威胁检测、微隔离、加密流量分析（ETA）</li></ul><hr><h3 id="五、数通全栈技术体系总览" tabindex="-1">五、数通全栈技术体系总览 <a class="header-anchor" href="#五、数通全栈技术体系总览" aria-label="Permalink to &quot;五、数通全栈技术体系总览&quot;">​</a></h3><h4 id="_1-协议栈分层-osi-tcp-ip" tabindex="-1">1. 协议栈分层（OSI/TCP/IP） <a class="header-anchor" href="#_1-协议栈分层-osi-tcp-ip" aria-label="Permalink to &quot;1. 协议栈分层（OSI/TCP/IP）&quot;">​</a></h4><ul><li>L2：以太网、VLAN、STP、LACP、802.11</li><li>L3：IP、ARP、ICMP、OSPF、IS-IS、BGP、IPv6</li><li>L4：TCP/UDP、端口、状态检测</li><li>L7：应用识别、DPI、HTTP/HTTPS、SSL、威胁防护</li></ul><h4 id="_2-跨设备通用技术" tabindex="-1">2. 跨设备通用技术 <a class="header-anchor" href="#_2-跨设备通用技术" aria-label="Permalink to &quot;2. 跨设备通用技术&quot;">​</a></h4><ul><li><strong>可靠性</strong>：VRRP、BFD、NSF、堆叠 / 集群、双机热备</li><li><strong>QoS</strong>：流量监管、队列调度、拥塞避免、整形</li><li><strong>管理</strong>：SNMP、NETCONF/YANG、RESTful API、自动化运维</li><li><strong>安全</strong>：ACL、802.1X、IPsec、SSL、NAT、日志审计</li></ul><h4 id="_3-主流厂商技术体系-apac-区" tabindex="-1">3. 主流厂商技术体系（APAC 区） <a class="header-anchor" href="#_3-主流厂商技术体系-apac-区" aria-label="Permalink to &quot;3. 主流厂商技术体系（APAC 区）&quot;">​</a></h4><ul><li>华为：VRP、iMaster NCE、敏捷交换机、NetEngine 路由器、USG 防火墙、AirEngine AP/AC</li><li>新华三：Comware、IRF、SecPath 防火墙、WX AC</li><li>锐捷：RGOS、MACC、RG-WALL 防火墙</li><li>深信服：NGAF、AC、VPN、SD-WAN</li></ul><hr><h3 id="六、学习路径与技能要求" tabindex="-1">六、学习路径与技能要求 <a class="header-anchor" href="#六、学习路径与技能要求" aria-label="Permalink to &quot;六、学习路径与技能要求&quot;">​</a></h3><ol><li><strong>基础</strong>：OSI/TCP/IP、IPv4/IPv6、子网划分、VLAN、STP、静态路由</li><li><strong>进阶</strong>：OSPF、BGP、MPLS、LACP、VRRP、NAT、ACL</li><li><strong>无线</strong>：802.11、AC+AP、CAPWAP、WPA3、射频优化</li><li><strong>安全</strong>：状态检测、NGFW、IPS、VPN、零信任</li><li><strong>实战</strong>：设备配置（华为 / 华三 / 锐捷）、排错、网络设计、SDN/SD-WAN</li></ol>',56)])])}const A=l(t,[["render",o]]);export{c as __pageData,A as default};
